import type { AstNode } from "./astTypes";
import { FUNCTION_SIGNATURES } from "./functionSignatures";

export class FormulaParseError extends Error {}

const ERROR_LITERALS = ["#DIV/0!", "#N/A", "#REF!", "#VALUE!", "#NAME?", "#NUM!", "#NULL!"];
const CELL_REF_RE = /^\$?[A-Z]{1,3}\$?\d{1,7}$/i;

export function parseFormula(formula: string): AstNode {
  const parser = new Parser(formula);
  return parser.parse();
}

class Parser {
  private i = 0;

  constructor(private readonly text: string) {}

  parse(): AstNode {
    this.skipWs();
    if (this.text[this.i] !== "=") throw new FormulaParseError("Formula must start with =.");
    this.i += 1;
    const child = this.expression();
    this.skipWs();
    if (this.i < this.text.length) throw new FormulaParseError(`Unexpected token at ${this.i}.`);
    return { kind: "root", child, start: 0, end: this.text.length };
  }

  private expression(): AstNode {
    return this.comparison();
  }

  private comparison(): AstNode {
    let left = this.concat();
    while (true) {
      this.skipWs();
      const op = this.matchAny(["<>", "<=", ">=", "=", "<", ">"]);
      if (!op) return left;
      const right = this.concat();
      left = { kind: "binaryOp", op, left, right, start: left.start, end: right.end };
    }
  }

  private concat(): AstNode {
    let left = this.additive();
    while (this.consume("&")) {
      const right = this.additive();
      left = { kind: "binaryOp", op: "&", left, right, start: left.start, end: right.end };
    }
    return left;
  }

  private additive(): AstNode {
    let left = this.multiplicative();
    while (true) {
      this.skipWs();
      const op = this.matchAny(["+", "-"]);
      if (!op) return left;
      const right = this.multiplicative();
      left = { kind: "binaryOp", op, left, right, start: left.start, end: right.end };
    }
  }

  private multiplicative(): AstNode {
    let left = this.power();
    while (true) {
      this.skipWs();
      const op = this.matchAny(["*", "/"]);
      if (!op) return left;
      const right = this.power();
      left = { kind: "binaryOp", op, left, right, start: left.start, end: right.end };
    }
  }

  private power(): AstNode {
    let left = this.unary();
    while (this.consume("^")) {
      const right = this.unary();
      left = { kind: "binaryOp", op: "^", left, right, start: left.start, end: right.end };
    }
    return left;
  }

  private unary(): AstNode {
    this.skipWs();
    const start = this.i;
    const op = this.matchAny(["+", "-"]);
    if (!op) return this.percent();
    const operand = this.unary();
    return { kind: "unaryOp", op, operand, start, end: operand.end };
  }

  private percent(): AstNode {
    const operand = this.primary();
    if (!this.consume("%")) return operand;
    return { kind: "percent", operand, start: operand.start, end: this.i };
  }

  private primary(): AstNode {
    this.skipWs();
    const start = this.i;
    if (this.i >= this.text.length) throw new FormulaParseError("Unexpected end of formula.");
    if (this.text[this.i] === "(") {
      this.i += 1;
      const child = this.expression();
      this.expect(")");
      return { kind: "parens", child, start, end: this.i };
    }
    if (this.text[this.i] === '"') return this.stringLiteral();

    const error = this.matchErrorLiteral();
    if (error) return { kind: "error", value: error, start, end: this.i };

    const number = this.numberLiteral();
    if (number) return number;

    return this.identifierLike();
  }

  private identifierLike(): AstNode {
    const start = this.i;
    const sheet = this.trySheetPrefix();
    const token = this.readIdentifierOrRef();
    if (!token) throw new FormulaParseError(`Expected expression at ${start}.`);

    this.skipWs();
    if (!sheet && this.consume("(")) {
      const args: AstNode[] = [];
      this.skipWs();
      if (!this.consume(")")) {
        while (true) {
          args.push(this.expression());
          this.skipWs();
          if (this.consume(")")) break;
          this.expect(",");
        }
      }
      const name = token.toUpperCase();
      const signature = FUNCTION_SIGNATURES[name];
      if (signature && args.length < signature.minArgs) {
        throw new FormulaParseError(`${name} expects at least ${signature.minArgs} args.`);
      }
      if (signature && signature.maxArgs !== null && args.length > signature.maxArgs) {
        throw new FormulaParseError(`${name} expects at most ${signature.maxArgs} args.`);
      }
      return { kind: "functionCall", name, args, start, end: this.i };
    }

    if (CELL_REF_RE.test(token)) {
      const firstAddress = token;
      this.skipWs();
      if (this.consume(":")) {
        const secondSheet = this.trySheetPrefix();
        const second = this.readIdentifierOrRef();
        if (!second || !CELL_REF_RE.test(second)) {
          throw new FormulaParseError(`Invalid range at ${start}.`);
        }
        return {
          kind: "rangeRef",
          sheet: secondSheet ?? sheet,
          address: `${firstAddress}:${second}`,
          start,
          end: this.i,
        };
      }
      return { kind: "cellRef", sheet, address: firstAddress, start, end: this.i };
    }

    if (token.toUpperCase() === "TRUE" || token.toUpperCase() === "FALSE") {
      return { kind: "boolean", value: token.toUpperCase() === "TRUE", start, end: this.i };
    }

    if (this.text[this.i] === "[" || token.includes("@")) {
      return this.readUnknown(start);
    }
    return { kind: "namedRange", name: token, start, end: this.i };
  }

  private trySheetPrefix(): string | null {
    const mark = this.i;
    let name: string | null = null;
    if (this.text[this.i] === "'") {
      this.i += 1;
      const start = this.i;
      while (this.i < this.text.length && this.text[this.i] !== "'") this.i += 1;
      if (this.text[this.i] !== "'") {
        this.i = mark;
        return null;
      }
      name = this.text.slice(start, this.i);
      this.i += 1;
    } else {
      const token = this.readBareSheetName();
      if (token) name = token;
    }
    if (name && this.text[this.i] === "!") {
      this.i += 1;
      return name;
    }
    this.i = mark;
    return null;
  }

  private readBareSheetName(): string | null {
    const start = this.i;
    while (/[A-Za-z0-9_.]/.test(this.text[this.i] ?? "")) this.i += 1;
    return this.i > start ? this.text.slice(start, this.i) : null;
  }

  private readIdentifierOrRef(): string | null {
    const start = this.i;
    while (/[A-Za-z0-9_.$]/.test(this.text[this.i] ?? "")) this.i += 1;
    return this.i > start ? this.text.slice(start, this.i) : null;
  }

  private readUnknown(start: number): AstNode {
    while (this.i < this.text.length && !/[,+\-*/^&=<>)]/.test(this.text[this.i])) this.i += 1;
    return { kind: "unknown", text: this.text.slice(start, this.i), start, end: this.i };
  }

  private stringLiteral(): AstNode {
    const start = this.i;
    this.i += 1;
    let value = "";
    while (this.i < this.text.length) {
      const ch = this.text[this.i];
      if (ch === '"' && this.text[this.i + 1] === '"') {
        value += '"';
        this.i += 2;
        continue;
      }
      if (ch === '"') {
        this.i += 1;
        return { kind: "string", value, start, end: this.i };
      }
      value += ch;
      this.i += 1;
    }
    throw new FormulaParseError("Unterminated string.");
  }

  private numberLiteral(): AstNode | null {
    const start = this.i;
    const re = /^(?:\d+\.\d*|\.\d+|\d+)(?:E[+-]?\d+)?/i;
    const match = this.text.slice(this.i).match(re);
    if (!match) return null;
    this.i += match[0].length;
    return { kind: "number", value: Number(match[0]), start, end: this.i };
  }

  private matchErrorLiteral(): string | null {
    for (const literal of ERROR_LITERALS) {
      if (this.text.slice(this.i, this.i + literal.length).toUpperCase() === literal) {
        this.i += literal.length;
        return literal;
      }
    }
    return null;
  }

  private skipWs(): void {
    while (/\s/.test(this.text[this.i] ?? "")) this.i += 1;
  }

  private consume(token: string): boolean {
    this.skipWs();
    if (this.text.slice(this.i, this.i + token.length) !== token) return false;
    this.i += token.length;
    return true;
  }

  private expect(token: string): void {
    if (!this.consume(token)) throw new FormulaParseError(`Expected ${token} at ${this.i}.`);
  }

  private matchAny(tokens: string[]): string | null {
    this.skipWs();
    for (const token of tokens) {
      if (this.text.slice(this.i, this.i + token.length) === token) {
        this.i += token.length;
        return token;
      }
    }
    return null;
  }
}
