/* global Excel */

const MAP_TAB_COLOR = "#F4B183";
const BASE_TAB_COLOR = "#A9D18E";
const DELTA_TAB_COLOR = "#F8CBAD";
const MAP_FORMULA_FILL = "#BFBFBF";
const MAP_NUMBER_FILL = "#BDD7EE";
const MAP_LABEL_FILL = "#FFF2CC";
const MAP_ERROR_FILL = "#FF0000";
const MAP_BLUE_FONT = "#0563C1";
const MAP_RED_FONT = "#FF0000";
const MAP_PREFIX = "Map - ";
const RED_DOT_FONT_SIZE = 13;

type CellCoord = { row: number; col: number };

let formulaMapNavigationRegistered = false;
let formulaMapNavigationBusy = false;
const formulaMapSources = new Map<string, string>();

export async function runFormulaMapTurbo(): Promise<void> {
  await ensureFormulaMapNavigation();
  await Excel.run(async (context) => {
    const source = context.workbook.worksheets.getActiveWorksheet();
    const used = source.getUsedRangeOrNullObject(true);
    source.load(["name", "position"]);
    used.load(["isNullObject", "rowIndex", "columnIndex", "rowCount", "columnCount", "values", "formulas", "formulasR1C1"]);
    await context.sync();
    if (used.isNullObject) return;

    const sourceName = source.name;
    const mapName = uniqueSheetName(`Map - ${sourceName}`);
    await deleteSheetIfExists(context, mapName);
    const map = context.workbook.worksheets.add(mapName);
    map.position = source.position + 1;
    map.tabColor = MAP_TAB_COLOR;

    const out: unknown[][] = [];
    const labelCells: CellCoord[] = [];
    const numberCells: CellCoord[] = [];
    const formulaCells: CellCoord[] = [];
    const flagCells: CellCoord[] = [];
    const errorCells: CellCoord[] = [];

    for (let r = 0; r < used.rowCount; r += 1) {
      const row: unknown[] = [];
      for (let c = 0; c < used.columnCount; c += 1) {
        const value = used.values[r][c];
        const formula = String(used.formulas[r][c] ?? "");
        const r1c1 = String(used.formulasR1C1[r][c] ?? "");
        const absRow = used.rowIndex + r;
        const absCol = used.columnIndex + c;

        if (formula.startsWith("=")) {
          if (isErrorValue(value)) {
            row.push(String(value));
            errorCells.push({ row: absRow, col: absCol });
            continue;
          }
          const left = c > 0 ? String(used.formulasR1C1[r][c - 1] ?? "") : "";
          const up = r > 0 ? String(used.formulasR1C1[r - 1][c] ?? "") : "";
          const sameLeft = left.startsWith("=") && left === r1c1;
          const sameUp = up.startsWith("=") && up === r1c1;
          const marker = sameLeft && sameUp ? "+" : sameLeft ? "<" : sameUp ? "^" : "\u25CF";
          row.push(marker);
          formulaCells.push({ row: absRow, col: absCol });
          if (marker === "\u25CF") {
            flagCells.push({ row: absRow, col: absCol });
          }
        } else if (typeof value === "number") {
          row.push(value);
          numberCells.push({ row: absRow, col: absCol });
        } else if (isErrorValue(value)) {
          row.push(String(value));
          errorCells.push({ row: absRow, col: absCol });
        } else if (value === null || value === "") {
          row.push("");
        } else {
          row.push(String(value));
          labelCells.push({ row: absRow, col: absCol });
        }
      }
      out.push(row);
    }

    const target = map.getRangeByIndexes(used.rowIndex, used.columnIndex, used.rowCount, used.columnCount);
    target.values = out;
    target.format.columnWidth = 22;
    target.format.rowHeight = 12;
    target.format.font.size = 7;
    target.format.font.name = "Arial";
    target.format.horizontalAlignment = Excel.HorizontalAlignment.center;

    applyStyle(map, cellsToRowRuns(formulaCells), { fill: MAP_FORMULA_FILL });
    applyStyle(map, cellsToRowRuns(flagCells), {
      fill: MAP_FORMULA_FILL,
      font: MAP_RED_FONT,
      bold: true,
      fontSize: RED_DOT_FONT_SIZE,
      alignment: Excel.HorizontalAlignment.center,
      verticalAlignment: Excel.VerticalAlignment.center,
    });
    applyStyle(map, cellsToRowRuns(numberCells), {
      fill: MAP_NUMBER_FILL,
      font: MAP_BLUE_FONT,
      alignment: Excel.HorizontalAlignment.right,
    });
    applyStyle(map, cellsToRowRuns(labelCells), {
      fill: MAP_LABEL_FILL,
      alignment: Excel.HorizontalAlignment.left,
    });
    applyStyle(map, cellsToRowRuns(errorCells), {
      fill: MAP_ERROR_FILL,
      font: "#FFFFFF",
      alignment: Excel.HorizontalAlignment.center,
    });
    formulaMapSources.set(mapName, sourceName);
    await context.sync();
  });
}

export async function ensureFormulaMapNavigation(): Promise<void> {
  if (formulaMapNavigationRegistered) return;
  await Excel.run(async (context) => {
    context.workbook.worksheets.onSelectionChanged.add(handleFormulaMapSelection);
    await context.sync();
    formulaMapNavigationRegistered = true;
  });
}

async function handleFormulaMapSelection(): Promise<void> {
  if (formulaMapNavigationBusy) return;
  formulaMapNavigationBusy = true;
  try {
    await Excel.run(async (context) => {
      const sheet = context.workbook.worksheets.getActiveWorksheet();
      const cell = context.workbook.getActiveCell();
      sheet.load("name");
      cell.load(["address", "values"]);
      await context.sync();

      const mapName = sheet.name;
      if (!mapName.startsWith(MAP_PREFIX)) return;
      if (String(cell.values?.[0]?.[0] ?? "") !== "\u25CF") return;

      const sourceName = formulaMapSources.get(mapName) ?? mapName.slice(MAP_PREFIX.length);
      const source = context.workbook.worksheets.getItemOrNullObject(sourceName);
      source.load("isNullObject");
      await context.sync();
      if (source.isNullObject) return;

      const address = String(cell.address).split("!").pop() ?? String(cell.address);
      source.activate();
      source.getRange(address).select();
      await context.sync();
    });
  } catch {
    // Map navigation is best-effort; leave the selected map cell unchanged on errors.
  } finally {
    formulaMapNavigationBusy = false;
  }
}

export async function createBaseDelta(): Promise<void> {
  await Excel.run(async (context) => {
    const source = context.workbook.worksheets.getActiveWorksheet();
    const used = source.getUsedRangeOrNullObject();
    source.load(["name", "position"]);
    used.load(["isNullObject", "rowIndex", "columnIndex", "rowCount", "columnCount", "values"]);
    await context.sync();
    if (used.isNullObject) return;

    const baseName = uniqueSheetName(`Base - ${source.name}`);
    const deltaName = uniqueSheetName(`Delta - ${source.name}`);
    const existingBase = context.workbook.worksheets.getItemOrNullObject(baseName);
    existingBase.load("isNullObject");
    await context.sync();
    if (!existingBase.isNullObject && !window.confirm(`${baseName} already exists. Reset Base/Delta snapshot?`)) {
      return;
    }

    await deleteSheetIfExists(context, baseName);
    await deleteSheetIfExists(context, deltaName);

    const base = source.copy(Excel.WorksheetPositionType.after, source);
    base.name = baseName;
    base.tabColor = BASE_TAB_COLOR;
    const delta = source.copy(Excel.WorksheetPositionType.after, base);
    delta.name = deltaName;
    delta.tabColor = DELTA_TAB_COLOR;
    await context.sync();

    const baseUsed = base.getRangeByIndexes(used.rowIndex, used.columnIndex, used.rowCount, used.columnCount);
    baseUsed.values = used.values;

    const deltaRange = delta.getRangeByIndexes(used.rowIndex, used.columnIndex, used.rowCount, used.columnCount);
    const deltaFormulas: unknown[][] = [];
    for (let r = 0; r < used.rowCount; r += 1) {
      const row: unknown[] = [];
      for (let c = 0; c < used.columnCount; c += 1) {
        const value = used.values[r][c];
        const cellAddress = a1(used.rowIndex + r, used.columnIndex + c);
        if (typeof value === "number") {
          row.push(`='${escapeSheetName(source.name)}'!${cellAddress}-'${escapeSheetName(baseName)}'!${cellAddress}`);
        } else {
          row.push(value);
        }
      }
      deltaFormulas.push(row);
    }
    deltaRange.formulas = deltaFormulas;
    await context.sync();
  });
}

export async function removeBaseDelta(): Promise<void> {
  await Excel.run(async (context) => {
    const source = context.workbook.worksheets.getActiveWorksheet();
    source.load("name");
    await context.sync();
    await deleteSheetIfExists(context, uniqueSheetName(`Base - ${source.name}`));
    await deleteSheetIfExists(context, uniqueSheetName(`Delta - ${source.name}`));
    await context.sync();
  });
}

function applyStyle(
  sheet: Excel.Worksheet,
  rangeAddresses: string[],
  style: {
    fill?: string;
    font?: string;
    alignment?: Excel.HorizontalAlignment;
    verticalAlignment?: Excel.VerticalAlignment;
    bold?: boolean;
    fontSize?: number;
  }
): void {
  for (const chunk of chunkAddresses(rangeAddresses)) {
    const range = sheet.getRanges(chunk.join(","));
    if (style.fill) {
      range.format.fill.pattern = "Solid";
      range.format.fill.color = style.fill;
    }
    if (style.font) range.format.font.color = style.font;
    if (style.bold !== undefined) range.format.font.bold = style.bold;
    if (style.fontSize !== undefined) range.format.font.size = style.fontSize;
    if (style.alignment) range.format.horizontalAlignment = style.alignment;
    if (style.verticalAlignment) range.format.verticalAlignment = style.verticalAlignment;
  }
}

function cellsToRowRuns(cells: CellCoord[]): string[] {
  if (cells.length === 0) return [];
  const sorted = [...cells].sort((a, b) => a.row - b.row || a.col - b.col);
  const runs: string[] = [];
  let start = sorted[0];
  let previous = sorted[0];
  for (let i = 1; i < sorted.length; i += 1) {
    const current = sorted[i];
    if (current.row === previous.row && current.col === previous.col + 1) {
      previous = current;
      continue;
    }
    runs.push(formatRun(start, previous));
    start = current;
    previous = current;
  }
  runs.push(formatRun(start, previous));
  return runs;
}

function formatRun(start: CellCoord, end: CellCoord): string {
  const first = a1(start.row, start.col);
  const last = a1(end.row, end.col);
  return first === last ? first : `${first}:${last}`;
}

async function deleteSheetIfExists(context: Excel.RequestContext, name: string): Promise<void> {
  const sheet = context.workbook.worksheets.getItemOrNullObject(name);
  sheet.load("isNullObject");
  await context.sync();
  if (!sheet.isNullObject) sheet.delete();
}

function chunkAddresses(addresses: string[]): string[][] {
  const chunks: string[][] = [];
  for (let i = 0; i < addresses.length; i += 180) chunks.push(addresses.slice(i, i + 180));
  return chunks;
}

function isErrorValue(value: unknown): boolean {
  return typeof value === "string" && value.startsWith("#") && value.endsWith("!");
}

function a1(rowIndex: number, colIndex: number): string {
  let col = "";
  let n = colIndex + 1;
  while (n > 0) {
    const rem = (n - 1) % 26;
    col = String.fromCharCode(65 + rem) + col;
    n = Math.floor((n - rem - 1) / 26);
  }
  return `${col}${rowIndex + 1}`;
}

function uniqueSheetName(name: string): string {
  return name.replace(/[\\/?*:[\]]/g, " ").slice(0, 31).trim();
}

function escapeSheetName(name: string): string {
  return name.replace(/'/g, "''");
}
