export type FunctionSignature = {
  args: string[];
  variadic?: boolean;
  minArgs: number;
  maxArgs: number | null;
};

export const FUNCTION_SIGNATURES: Record<string, FunctionSignature> = {
  SUM: { args: ["number1"], variadic: true, minArgs: 1, maxArgs: null },
  SUMIF: { args: ["range", "criteria", "sum_range"], minArgs: 2, maxArgs: 3 },
  SUMIFS: { args: ["sum_range", "criteria_range1", "criteria1"], variadic: true, minArgs: 3, maxArgs: null },
  SUMPRODUCT: { args: ["array1"], variadic: true, minArgs: 1, maxArgs: null },
  AVERAGE: { args: ["number1"], variadic: true, minArgs: 1, maxArgs: null },
  AVERAGEIF: { args: ["range", "criteria", "average_range"], minArgs: 2, maxArgs: 3 },
  AVERAGEIFS: { args: ["average_range", "criteria_range1", "criteria1"], variadic: true, minArgs: 3, maxArgs: null },
  COUNT: { args: ["value1"], variadic: true, minArgs: 1, maxArgs: null },
  COUNTA: { args: ["value1"], variadic: true, minArgs: 1, maxArgs: null },
  COUNTIF: { args: ["range", "criteria"], minArgs: 2, maxArgs: 2 },
  COUNTIFS: { args: ["criteria_range1", "criteria1"], variadic: true, minArgs: 2, maxArgs: null },
  MIN: { args: ["number1"], variadic: true, minArgs: 1, maxArgs: null },
  MAX: { args: ["number1"], variadic: true, minArgs: 1, maxArgs: null },
  VLOOKUP: { args: ["lookup_value", "table_array", "col_index_num", "range_lookup"], minArgs: 3, maxArgs: 4 },
  HLOOKUP: { args: ["lookup_value", "table_array", "row_index_num", "range_lookup"], minArgs: 3, maxArgs: 4 },
  XLOOKUP: { args: ["lookup_value", "lookup_array", "return_array", "if_not_found", "match_mode", "search_mode"], minArgs: 3, maxArgs: 6 },
  INDEX: { args: ["array", "row_num", "column_num", "area_num"], minArgs: 2, maxArgs: 4 },
  MATCH: { args: ["lookup_value", "lookup_array", "match_type"], minArgs: 2, maxArgs: 3 },
  XMATCH: { args: ["lookup_value", "lookup_array", "match_mode", "search_mode"], minArgs: 2, maxArgs: 4 },
  OFFSET: { args: ["reference", "rows", "cols", "height", "width"], minArgs: 3, maxArgs: 5 },
  INDIRECT: { args: ["ref_text", "a1"], minArgs: 1, maxArgs: 2 },
  CHOOSE: { args: ["index_num", "value1"], variadic: true, minArgs: 2, maxArgs: null },
  IF: { args: ["logical_test", "value_if_true", "value_if_false"], minArgs: 2, maxArgs: 3 },
  IFS: { args: ["logical_test1", "value_if_true1"], variadic: true, minArgs: 2, maxArgs: null },
  IFERROR: { args: ["value", "value_if_error"], minArgs: 2, maxArgs: 2 },
  IFNA: { args: ["value", "value_if_na"], minArgs: 2, maxArgs: 2 },
  AND: { args: ["logical1"], variadic: true, minArgs: 1, maxArgs: null },
  OR: { args: ["logical1"], variadic: true, minArgs: 1, maxArgs: null },
  NOT: { args: ["logical"], minArgs: 1, maxArgs: 1 },
  LEFT: { args: ["text", "num_chars"], minArgs: 1, maxArgs: 2 },
  RIGHT: { args: ["text", "num_chars"], minArgs: 1, maxArgs: 2 },
  MID: { args: ["text", "start_num", "num_chars"], minArgs: 3, maxArgs: 3 },
  LEN: { args: ["text"], minArgs: 1, maxArgs: 1 },
  CONCAT: { args: ["text1"], variadic: true, minArgs: 1, maxArgs: null },
  CONCATENATE: { args: ["text1"], variadic: true, minArgs: 1, maxArgs: null },
  ROUND: { args: ["number", "num_digits"], minArgs: 2, maxArgs: 2 },
  ROUNDUP: { args: ["number", "num_digits"], minArgs: 2, maxArgs: 2 },
  ROUNDDOWN: { args: ["number", "num_digits"], minArgs: 2, maxArgs: 2 },
  ABS: { args: ["number"], minArgs: 1, maxArgs: 1 },
  MOD: { args: ["number", "divisor"], minArgs: 2, maxArgs: 2 },
  TODAY: { args: [], minArgs: 0, maxArgs: 0 },
  NOW: { args: [], minArgs: 0, maxArgs: 0 },
  DATE: { args: ["year", "month", "day"], minArgs: 3, maxArgs: 3 },
};

export function resolveFunctionArgName(functionName: string, index: number): string {
  const signature = FUNCTION_SIGNATURES[functionName.toUpperCase()];
  if (!signature) return `arg${index + 1}`;
  if (index < signature.args.length) return signature.args[index];
  if (!signature.variadic || signature.args.length === 0) return `arg${index + 1}`;
  const base = signature.args[signature.args.length - 1];
  return `${base.replace(/\d+$/, "")}${index + 1}`;
}
