/* global Office */

import { openFormulaExplorerDialog } from "./formulaExplorerLauncher";
import {
  createBaseDelta,
  removeBaseDelta,
  runFormulaMapTurbo,
} from "./traceForgeActions";

async function finish(event: Office.AddinCommands.Event, work: () => Promise<void>): Promise<void> {
  try {
    await work();
  } catch (error) {
    // eslint-disable-next-line no-console
    console.error("[TraceForge ribbon]", error);
  } finally {
    event.completed();
  }
}

Office.actions.associate("runFormulaMapTurbo", (event) =>
  finish(event, () => runFormulaMapTurbo())
);
Office.actions.associate("createBaseDelta", (event) => finish(event, () => createBaseDelta()));
Office.actions.associate("removeBaseDelta", (event) => finish(event, () => removeBaseDelta()));
Office.actions.associate("exploreFormula", (event) =>
  finish(event, () => openFormulaExplorerDialog())
);
